import React, { useEffect, useRef } from "react";

function DangerAlertPopup({ message, onConfirm, onCancel }) {
  const modalRef = useRef(null);
  const confirmButtonRef = useRef(null);

  // Handle escape key and focus management
  useEffect(() => {
    const handleKeyDown = (e) => {
      if (e.key === "Escape") onCancel();
      if (e.key === "Enter") onConfirm();
    };

    document.addEventListener("keydown", handleKeyDown);
    confirmButtonRef.current.focus();

    // Prevent body scrolling when modal is open
    document.body.style.overflow = "hidden";

    return () => {
      document.removeEventListener("keydown", handleKeyDown);
      document.body.style.overflow = "unset";
    };
  }, [onConfirm, onCancel]);

  return (
    <div
      className="modal-backdrop"
      style={{
        position: "fixed",
        top: 0,
        left: 0,
        width: "100%",
        height: "100%",
        backgroundColor: "rgba(0, 0, 0, 0.7)",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        zIndex: 9999,
        opacity: 0,
        animation: "fadeIn 0.3s ease-out forwards",
        backdropFilter: "blur(8px)",
        WebkitBackdropFilter: "blur(8px)",
      }}
      onClick={onCancel}
    >
      <div
        ref={modalRef}
        className="modal-content"
        style={{
          backgroundColor: "white",
          padding: "2rem",
          borderRadius: "20px",
          boxShadow: "0 25px 50px -12px rgba(0, 0, 0, 0.25), 0 0 0 1px rgba(220, 53, 69, 0.1)",
          maxWidth: "480px",
          width: "90%",
          transform: "scale(0.9) translateY(-20px)",
          animation: "scaleIn 0.3s cubic-bezier(0.34, 1.2, 0.64, 1) forwards",
          border: "none",
          fontFamily: "'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif",
        }}
        onClick={(e) => e.stopPropagation()}
      >
        <div
          className="modal-icon"
          style={{
            textAlign: "center",
            marginBottom: "1.5rem",
          }}
        >
          <div
            style={{
              width: "64px",
              height: "64px",
              margin: "0 auto",
              background: "linear-gradient(135deg, #fff5f5 0%, #ffe3e3 100%)",
              borderRadius: "50%",
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
              animation: "pulseWarning 1.5s ease-in-out infinite",
            }}
          >
            <svg
              width="32"
              height="32"
              viewBox="0 0 24 24"
              fill="none"
              xmlns="http://www.w3.org/2000/svg"
              style={{ color: "#dc3545" }}
            >
              <path
                d="M12 9V14M12 17V17.01M5.07183 19H18.9282C20.4678 19 21.4301 17.3333 20.6603 16L13.7321 4C12.9623 2.66667 11.0378 2.66667 10.268 4L3.33978 16C2.56998 17.3333 3.53223 19 5.07183 19Z"
                stroke="currentColor"
                strokeWidth="2"
                strokeLinecap="round"
                strokeLinejoin="round"
              />
            </svg>
          </div>
        </div>

        <h3
          className="modal-title"
          style={{
            textAlign: "center",
            margin: "0 0 0.75rem 0",
            color: "#1e293b",
            fontSize: "1.5rem",
            fontWeight: "600",
            letterSpacing: "-0.01em",
          }}
        >
          Confirm Action
        </h3>

        <p
          className="modal-message"
          style={{
            textAlign: "center",
            margin: "0 0 2rem 0",
            color: "#475569",
            fontSize: "0.9rem",
            lineHeight: "1.5",
            fontWeight: "500",
          }}
        >
          {message}
        </p>

        <div
          className="modal-actions"
          style={{
            display: "flex",
            justifyContent: "center",
            gap: "1rem",
          }}
        >
          <button
            type="button"
            className="btn-cancel"
            onClick={onCancel}
            style={{
              padding: "0.75rem 1.75rem",
              backgroundColor: "#f1f5f9",
              color: "#475569",
              border: "none",
              borderRadius: "10px",
              fontWeight: "500",
              fontSize: "0.875rem",
              cursor: "pointer",
              transition: "all 0.2s cubic-bezier(0.4, 0, 0.2, 1)",
              minWidth: "110px",
              letterSpacing: "0.3px",
            }}
            onMouseOver={(e) => {
              e.target.style.backgroundColor = "#e2e8f0";
              e.target.style.transform = "translateY(-1px)";
            }}
            onMouseOut={(e) => {
              e.target.style.backgroundColor = "#f1f5f9";
              e.target.style.transform = "translateY(0)";
            }}
          >
            Cancel
          </button>
          <button
            type="button"
            className="btn-confirm"
            ref={confirmButtonRef}
            onClick={onConfirm}
            style={{
              padding: "0.75rem 1.75rem",
              backgroundColor: "#dc3545",
              color: "white",
              border: "none",
              borderRadius: "10px",
              fontWeight: "500",
              fontSize: "0.875rem",
              cursor: "pointer",
              transition: "all 0.2s cubic-bezier(0.4, 0, 0.2, 1)",
              minWidth: "110px",
              boxShadow: "0 4px 12px rgba(220, 53, 69, 0.25)",
              letterSpacing: "0.3px",
            }}
            onMouseOver={(e) => {
              e.target.style.backgroundColor = "#c82333";
              e.target.style.transform = "translateY(-1px)";
              e.target.style.boxShadow = "0 6px 16px rgba(220, 53, 69, 0.35)";
            }}
            onMouseOut={(e) => {
              e.target.style.backgroundColor = "#dc3545";
              e.target.style.transform = "translateY(0)";
              e.target.style.boxShadow = "0 4px 12px rgba(220, 53, 69, 0.25)";
            }}
          >
            Confirm
          </button>
        </div>
      </div>

      <style>
        {`
          @keyframes fadeIn {
            from { 
              opacity: 0;
              backdrop-filter: blur(0px);
              -webkit-backdrop-filter: blur(0px);
            }
            to { 
              opacity: 1;
              backdrop-filter: blur(8px);
              -webkit-backdrop-filter: blur(8px);
            }
          }
          
          @keyframes scaleIn {
            from { 
              transform: scale(0.95) translateY(-30px);
              opacity: 0;
            }
            to { 
              transform: scale(1) translateY(0);
              opacity: 1;
            }
          }
          
          @keyframes pulseWarning {
            0% { 
              transform: scale(1);
              box-shadow: 0 0 0 0 rgba(220, 53, 69, 0.2);
            }
            50% { 
              transform: scale(1.05);
              box-shadow: 0 0 0 8px rgba(220, 53, 69, 0);
            }
            100% { 
              transform: scale(1);
              box-shadow: 0 0 0 0 rgba(220, 53, 69, 0);
            }
          }
          
          .btn-cancel:focus, .btn-confirm:focus {
            outline: 2px solid #3d8bfd;
            outline-offset: 2px;
          }
          
          .modal-content {
            backdrop-filter: blur(0px);
          }
        `}
      </style>
    </div>
  );
}

export default DangerAlertPopup;